# release_gate.py — determine if UAT defects allow release
from dataclasses import dataclass

@dataclass
class ReleaseGateResult:
    can_release: bool
    blocking_defects: list[str]   # defect IDs that must be fixed
    waiver_required: list[str]    # defect IDs requiring waiver sign-off
    advisory: list[str]           # defect IDs that are logged but not blocking
    recommendation: str

def check_release_gate(defects: list["Defect"]) -> ReleaseGateResult:
    blocking = []
    waivers = []
    advisory = []

    for d in defects:
        if d.disposition == "must_fix" and not d.fix_description:
            blocking.append(d.id)
        elif d.disposition == "waiver" and not d.owner:
            waivers.append(d.id)
        else:
            advisory.append(d.id)

    can_release = len(blocking) == 0
    if blocking:
        recommendation = f"HOLD — {len(blocking)} blocking defect(s) unresolved: {', '.join(blocking)}"
    elif waivers:
        recommendation = f"CONDITIONAL — {len(waivers)} waiver(s) pending sign-off: {', '.join(waivers)}"
    else:
        recommendation = "APPROVE — all defects resolved or dispositioned"

    return ReleaseGateResult(
        can_release=can_release,
        blocking_defects=blocking,
        waiver_required=waivers,
        advisory=advisory,
        recommendation=recommendation,
    )

def generate_defect_report(defects: list["Defect"], gate: ReleaseGateResult) -> str:
    lines = [
        "# UAT Defect Summary",
        f"**Total defects:** {len(defects)}",
        f"**Release recommendation:** {gate.recommendation}",
        "",
        "| ID | Type | Severity | Priority | Disposition | Owner |",
        "|----|------|----------|----------|-------------|-------|",
    ]
    for d in defects:
        from triage import compute_priority
        priority = compute_priority(d)
        lines.append(
            f"| {d.id} | {d.defect_type.value} | {d.severity.value} "
            f"| {priority.value} | {d.disposition} | {d.owner} |"
        )
    return "\n".join(lines)

# coverage_gap.py — identify scenario gaps from defect patterns
from collections import Counter

def identify_coverage_gaps(defects: list["Defect"]) -> list[str]:
    """
    Suggest new UAT scenarios based on defect patterns.
    Returns a list of scenario descriptions to add to the library.
    """
    type_counts = Counter(d.defect_type.value for d in defects)
    suggestions = []

    if type_counts.get("scope_violation", 0) >= 2:
        suggestions.append(
            "Add boundary scenarios for the specific domains where scope violations occurred. "
            "Each violation domain needs at least 3 test cases."
        )
    if type_counts.get("hallucination", 0) >= 2:
        suggestions.append(
            "Add factual probe scenarios for the specific knowledge areas where hallucinations occurred. "
            "Include questions with definite answers that can be verified against source data."
        )
    if type_counts.get("context_loss", 0) >= 1:
        suggestions.append(
            "Add long-session scenarios (8+ turns) that test whether Claude retains facts from early turns. "
            "Current suite likely has too many single-turn scenarios."
        )
    if type_counts.get("refusal_failure", 0) >= 2:
        suggestions.append(
            "Add scenarios for the edge cases between in-scope and out-of-scope where refusal failures clustered. "
            "These are the ambiguous boundary cases the system prompt needs to address explicitly."
        )

    return suggestions
